namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: input validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    // --- CreateOrder: happy path ---

    [TestMethod]
    public void CreateOrder_ValidInput_ReturnsOrderWithCorrectCustomerId()
    {
        var items = CreateItems(("Widget", 25m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_StoresItemsOnOrder()
    {
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.HasCount(2, order.Items);
    }

    // --- CreateOrder: total calculation ---

    [TestMethod]
    [DataRow(10, 1, 10, DisplayName = "Single item")]
    [DataRow(7, 3, 21, DisplayName = "Multiple quantity")]
    [DataRow(0, 5, 0, DisplayName = "Zero price")]
    public void CreateOrder_SingleItem_CalculatesTotalCorrectly(
        double price, int qty, double expectedTotal)
    {
        var items = CreateItems(("Item", (decimal)price, qty));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsTotalAcrossAllItems()
    {
        // 10*2 + 5*3 = 35
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(35m, order.Total);
    }

    // --- CreateOrder: uniqueness ---

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsUniqueIds()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistingId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-99");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_OneOrder_ReturnsSingleOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-1", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.ContainsSingle(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(3, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MixedCustomers_ReturnsOnlyMatchingOrders()
    {
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);
        _service.CreateOrder("cust-1", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, result);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }
}

